INSERT INTO `alerts` (`type`, `level`, `title`, `content`, `sea_area`, `start_time`, `end_time`, `status`, `create_by`) VALUES
('TYPHOON', 'ORANGE', '台风橙色预警：南海热带气旋', '预计未来24小时内，南海中部海域将出现8-10级大风，浪高3-5米。请过往船只注意避风，养殖户加固网箱设施。', '南海中部', '2025-06-01 08:00:00', '2025-06-03 08:00:00', 'ACTIVE', 1),
('EXTREME_TEMP', 'YELLOW', '高温黄色预警：湛江近海', '湛江近海表层水温连续3日超过32℃，可能引发珊瑚白化和养殖鱼类应激反应。建议养殖户增加换水量，开启增氧设备。', '湛江海域', '2025-06-01 06:00:00', '2025-06-04 06:00:00', 'ACTIVE', 1),
('TIDE', 'INFO', '天文大潮提醒', '受月球引力影响，明后两天南海沿岸将迎来天文大潮，潮差可达2.5米。沿海低洼地区请注意防范海水倒灌。', '南海沿岸', '2025-06-02 00:00:00', '2025-06-04 00:00:00', 'ACTIVE', 1);
