INSERT INTO `knowledge` (`title`, `category`, `summary`, `content`, `author`, `status`) VALUES
('南海的洋流系统：大自然的蓝色动脉', 'OCEAN_CURRENT', '介绍南海表层环流和深层环流的基本特征', '# 南海的洋流系统\n\n南海是西太平洋最大的边缘海之一，其洋流系统复杂而有趣。\n\n## 表层环流\n\n南海表层环流受季风控制，具有明显的季节变化：\n\n- **冬季**（11月-3月）：东北季风驱动，表层水整体向西南方向流动\n- **夏季**（6月-9月）：西南季风驱动，表层水向东北方向流动\n\n## 深层环流\n\n南海深层水主要通过吕宋海峡与太平洋进行交换...\n\n> 洋流数据来源于国家地球系统科学数据中心南海再分析数据集（1986年至今）。', '管理员', 'PUBLISHED'),
('潮汐的奥秘：为什么海水会"呼吸"', 'TIDE', '通俗解释潮汐的形成原理与南海潮汐特征', '# 潮汐的奥秘\n\n海水每天两次的涨落，像地球的"呼吸"一样有规律。\n\n## 潮汐的成因\n\n潮汐主要由月球和太阳的引力引起...\n\n## 南海潮汐特征\n\n南海以不规则全日潮和半日潮为主，潮差一般在1-3米之间。\n\n北部湾的潮差最大可达4米以上，是世界上著名的强潮区之一。', '管理员', 'PUBLISHED'),
('海洋污染监测：守护蓝色家园', 'POLLUTION', '介绍海洋污染的来源、类型与监测手段', '# 海洋污染监测\n\n## 污染来源\n\n1. **陆源污染**：工业废水、农业径流、生活污水\n2. **海上污染**：船舶排放、石油泄漏、养殖污染\n3. **大气沉降**：重金属、持久性有机污染物\n\n## 监测指标\n\n- 化学需氧量（COD）\n- 石油类\n- 重金属（汞、镉、铅）\n- 微塑料\n\n## 南海污染现状\n\n珠江口是南海污染物输入的主要通道...', '管理员', 'PUBLISHED'),
('南海地理概况：蓝色国土的范围与特征', 'GEOGRAPHY', '介绍南海的地理位置、面积、边界范围、周边国家及主要岛礁', '# 南海地理概况\n\n南海（South China Sea）是西太平洋最大的边缘海之一，位于中国大陆以南，是中国三大边缘海之一。\n\n## 地理位置\n\n南海北起中国大陆（约北纬23°），南至加里曼丹岛（约南纬3°），西起中南半岛（约东经105°），东至菲律宾群岛（约东经121°）。\n\n## 面积与边界\n\n南海总面积约350万平方公里，其中中国主张管辖的海域面积约210万平方公里。南海通过多个海峡与周边海域相连：\n\n- **北**：台湾海峡连接东海\n- **东北**：巴士海峡连接太平洋\n- **东南**：民都洛海峡、巴拉巴克海峡连接苏禄海\n- **南**：卡里马塔海峡连接爪哇海\n- **西南**：马六甲海峡连接印度洋\n\n## 主要岛礁\n\n南海有四大群岛：东沙群岛、西沙群岛、中沙群岛和南沙群岛。南沙群岛是南海诸岛中分布最广、岛礁数量最多的群岛。\n\n## 海底地形\n\n南海海底地形复杂，中部为深海盆（水深3000-4000米），四周为大陆架。最大水深超过5000米。', '管理员', 'PUBLISHED'),
('南海水温与盐度：海洋的"体温"与"咸度"', 'WATER_QUALITY', '介绍南海海水温度和盐度的时空分布特征及影响因素', '# 南海水温与盐度\n\n海水温度和盐度是描述海洋环境最基础的两个物理参数，它们直接影响海洋环流、生物分布和气候系统。\n\n## 海水温度\n\n南海表层水温常年较高，具有明显的季节变化：\n\n- **冬季**（12月-2月）：北部约20-24°C，南部约26-28°C\n- **夏季**（6月-8月）：全海域约28-30°C，分布均匀\n- **年平均**：约27°C，属热带-亚热带海域\n\n水温垂直分布呈现明显的层化特征：表层混合层（0-50米）、温跃层（50-200米，温度骤降）、深层（200米以下，温度缓慢下降至2-4°C）。\n\n## 海水盐度\n\n南海表层盐度一般在32-34 PSU之间：\n\n- **雨季**（夏季）：珠江等河流输入大量淡水，沿岸盐度降低至30 PSU以下\n- **旱季**（冬季）：蒸发增强，盐度升高至34 PSU以上\n- **深海区**：盐度稳定在34.5-34.6 PSU\n\n## 数据来源\n\n本系统水温、盐度数据源于国家地球系统科学数据中心南海再分析数据集。', '管理员', 'PUBLISHED'),
('南海海洋生态保护：守护生物多样性宝库', 'ECOLOGY', '介绍南海海洋生态系统类型、生物多样性及保护措施', '# 南海海洋生态保护\n\n南海是全球海洋生物多样性最丰富的海域之一，拥有珊瑚礁、红树林、海草床等多种典型海洋生态系统。\n\n## 生物多样性\n\n南海已记录的海洋生物超过2万种，包括：\n\n- **鱼类**：约2000种，如金枪鱼、石斑鱼、鲷鱼等经济鱼类\n- **珊瑚**：约500种，主要分布在西沙、南沙群岛\n- **海洋哺乳动物**：中华白海豚、儒艮等珍稀物种\n- **海龟**：绿海龟、玳瑁等\n\n## 生态系统类型\n\n1. **珊瑚礁生态系统**：\"海洋热带雨林\"，为25%的海洋生物提供栖息地\n2. **红树林生态系统**：海岸卫士，具有防风消浪、净化水质的功能\n3. **海草床生态系统**：儒艮等濒危物种的觅食地\n\n## 面临的威胁\n\n- 气候变化导致珊瑚白化\n- 过度捕捞破坏食物链\n- 陆源污染输入营养盐\n- 海岸开发破坏栖息地\n\n## 保护措施\n\n中国已建立多个海洋自然保护区，如三亚珊瑚礁国家级自然保护区、东寨港红树林自然保护区等。同时推行伏季休渔制度，促进渔业资源恢复。', '管理员', 'PUBLISHED');
